import{_ as i,o as t,c as a,ae as l}from"./chunks/framework.CB71nIlf.js";const d=JSON.parse('{"title":"Experimenter Manual","description":"","frontmatter":{},"headers":[],"relativePath":"en/2-experimenter-manual/index.md","filePath":"en/2-experimenter-manual/index.md"}'),n={name:"en/2-experimenter-manual/index.md"};function r(o,e,s,p,m,u){return t(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="experimenter-manual" tabindex="-1">Experimenter Manual <a class="header-anchor" href="#experimenter-manual" aria-label="Permalink to &quot;Experimenter Manual&quot;">​</a></h1><p>Welcome to the CogniAND Psychology Experiment Platform! This manual will help you understand how to use the platform&#39;s features as an experimenter (researcher).</p><h2 id="what-is-an-experimenter" tabindex="-1">What is an Experimenter? <a class="header-anchor" href="#what-is-an-experimenter" aria-label="Permalink to &quot;What is an Experimenter?&quot;">​</a></h2><p>An experimenter is the designer and manager of experiments, responsible for creating experiments, recruiting subjects, and managing experimental data. On the CogniAND platform, experimenters can:</p><ul><li>✅ View and manage experiments they created</li><li>✅ Use the invitation system to recruit subjects</li><li>✅ Use experiment templates to quickly create experiments</li><li>✅ Manage personal profile and roles</li><li>⚠️ View experiment data (partial placeholder)</li><li>❌ Create and edit experiments (not fully implemented)</li></ul><h2 id="quick-navigation" tabindex="-1">Quick Navigation <a class="header-anchor" href="#quick-navigation" aria-label="Permalink to &quot;Quick Navigation&quot;">​</a></h2><h3 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h3><ul><li><a href="./1-getting-started.html">Quick Start</a> - Understand experimenter features in 5 minutes</li><li><a href="./2-registration-login.html">Registration &amp; Login</a> - Create an experimenter account</li></ul><h3 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h3><ul><li><a href="./3-experiment-management/">Experiment Management</a> - View, create, and publish experiments</li><li><a href="./4-template-library.html">Template Library</a> - Use templates to quickly create experiments</li><li><a href="./5-invite-system/">Invitation System</a> - Recruit subjects for experiments</li><li><a href="./6-data-management.html">Data Management</a> - View and export experiment data</li><li><a href="./7-backstage.html">Backstage</a> - Experimenter workspace features</li></ul><h3 id="important-information" tabindex="-1">Important Information <a class="header-anchor" href="#important-information" aria-label="Permalink to &quot;Important Information&quot;">​</a></h3><ul><li><a href="./8-permissions.html">Permissions</a> - Understand experimenter permissions and guidelines</li></ul><h2 id="feature-status" tabindex="-1">Feature Status <a class="header-anchor" href="#feature-status" aria-label="Permalink to &quot;Feature Status&quot;">​</a></h2><h3 id="✅-fully-implemented-features" tabindex="-1">✅ Fully Implemented Features <a class="header-anchor" href="#✅-fully-implemented-features" aria-label="Permalink to &quot;✅ Fully Implemented Features&quot;">​</a></h3><ol><li><p><strong>Registration &amp; Login</strong></p><ul><li>Standard registration (email + password)</li><li>Email verification</li><li>Password recovery</li><li>Auto-login</li></ul></li><li><p><strong>View Experiments</strong></p><ul><li>View list of experiments you created</li><li>View experiment details and statistics</li></ul></li><li><p><strong>Invitation System</strong></p><ul><li>Generate experiment invitation links</li><li>Send invitation emails to subjects</li><li>Share invitation links on social media</li><li>Verify invitation code validity</li></ul></li><li><p><strong>Personal Center</strong></p><ul><li>Manage personal profile</li><li>Switch to subject role (if applicable)</li><li>View messages and notifications</li></ul></li></ol><h3 id="❌-not-implemented-features" tabindex="-1">❌ Not Implemented Features <a class="header-anchor" href="#❌-not-implemented-features" aria-label="Permalink to &quot;❌ Not Implemented Features&quot;">​</a></h3><ol><li><p><strong>Experiment Creation &amp; Editing</strong></p><ul><li>Frontend has complete experiment creation interface</li><li>Backend lacks corresponding implementation</li><li>Cannot save and publish new experiments</li></ul></li><li><p><strong>Experiment Publishing Management</strong></p><ul><li>Cannot modify experiment status (draft/published/closed)</li><li>Cannot set experiment visibility</li></ul></li></ol><h3 id="⚠️-partially-implemented-placeholder-features" tabindex="-1">⚠️ Partially Implemented/Placeholder Features <a class="header-anchor" href="#⚠️-partially-implemented-placeholder-features" aria-label="Permalink to &quot;⚠️ Partially Implemented/Placeholder Features&quot;">​</a></h3><ol><li><p><strong>Subject Application Management</strong> (API returns empty list)</p><ul><li>View subject applications</li><li>Approve or reject applications</li></ul></li><li><p><strong>Experiment Data Viewing</strong> (placeholder API)</p><ul><li>View data submitted by subjects</li><li>Data statistics and analysis</li><li>Data export functionality</li></ul></li></ol><h2 id="typical-workflow" tabindex="-1">Typical Workflow <a class="header-anchor" href="#typical-workflow" aria-label="Permalink to &quot;Typical Workflow&quot;">​</a></h2><h3 id="experimenter-publishing-experiment-process-some-features-not-implemented" tabindex="-1">Experimenter Publishing Experiment Process (Some features not implemented) <a class="header-anchor" href="#experimenter-publishing-experiment-process-some-features-not-implemented" aria-label="Permalink to &quot;Experimenter Publishing Experiment Process (Some features not implemented)&quot;">​</a></h3><ol><li><p><strong>Create Experiment</strong> (❌ Not Implemented)</p><ul><li>Log in to experimenter account</li><li>Enter &quot;Experimenter Backstage&quot;</li><li>Click &quot;Create New Experiment&quot;</li><li>Fill in basic experiment information</li><li>Configure experiment paradigm and materials</li><li>Set recruitment conditions</li></ul></li><li><p><strong>Publish Experiment</strong> (❌ Not Implemented)</p><ul><li>Preview experiment content</li><li>Choose publishing method (public/private)</li><li>Click &quot;Publish&quot; button</li></ul></li><li><p><strong>Recruit Subjects</strong> (✅ Implemented)</p><ul><li>Generate invitation link to share with target subjects</li><li>Or send invitation emails</li><li>Wait for subject applications</li></ul></li><li><p><strong>Manage Applications</strong> (⚠️ Placeholder)</p><ul><li>View subject application list</li><li>Review subject qualifications</li><li>Approve or reject applications</li></ul></li><li><p><strong>Monitor Progress</strong> (⚠️ Placeholder)</p><ul><li>View number of experiment participants</li><li>View data collection progress</li><li>Receive completion notifications</li></ul></li><li><p><strong>Data Management</strong> (⚠️ Placeholder)</p><ul><li>View data submitted by subjects</li><li>Export data for analysis</li><li>Generate experiment reports</li></ul></li></ol><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><h3 id="what-experimenters-can-do" tabindex="-1">What Experimenters Can Do <a class="header-anchor" href="#what-experimenters-can-do" aria-label="Permalink to &quot;What Experimenters Can Do&quot;">​</a></h3><ul><li>✅ View experiments they created</li><li>✅ Generate and manage invitation links</li><li>✅ Send invitation emails</li><li>✅ Manage personal profile</li><li>✅ Switch roles (if also a subject)</li><li>⚠️ View experiment data (placeholder)</li><li>❌ Create new experiments (not implemented)</li><li>❌ Edit published experiments (not implemented)</li></ul><h3 id="what-experimenters-cannot-do" tabindex="-1">What Experimenters Cannot Do <a class="header-anchor" href="#what-experimenters-cannot-do" aria-label="Permalink to &quot;What Experimenters Cannot Do&quot;">​</a></h3><ul><li>❌ View other experimenters&#39; experiment data</li><li>❌ Modify other experimenters&#39; experiments</li><li>❌ View subjects&#39; personal privacy information</li><li>❌ Delete data submitted by subjects</li><li>❌ Access administrator functions</li></ul><h2 id="important-notes" tabindex="-1">Important Notes <a class="header-anchor" href="#important-notes" aria-label="Permalink to &quot;Important Notes&quot;">​</a></h2><h3 id="experimental-ethics" tabindex="-1">Experimental Ethics <a class="header-anchor" href="#experimental-ethics" aria-label="Permalink to &quot;Experimental Ethics&quot;">​</a></h3><p>As an experimenter, you need to follow psychology research ethics standards:</p><ol><li><p><strong>Respect Principle</strong></p><ul><li>Respect subjects&#39; autonomy</li><li>Protect subjects&#39; privacy and dignity</li><li>Do not discriminate or insult subjects</li></ul></li><li><p><strong>Beneficence Principle</strong></p><ul><li>Experiments should have scientific value and social significance</li><li>Maximize experiment benefits, minimize risks</li><li>Provide timely feedback to subjects (if applicable)</li></ul></li><li><p><strong>Justice Principle</strong></p><ul><li>Fair selection of subjects, no discrimination</li><li>Reasonable distribution of experiment benefits and risks</li><li>Protect vulnerable groups&#39; rights</li></ul></li><li><p><strong>Integrity Principle</strong></p><ul><li>Truthfully describe experiment content and risks</li><li>Do not forge or tamper with data</li><li>Respect academic norms and intellectual property</li></ul></li></ol><p>For details, see: <a href="/cogniand-manual.github.io/en/5-data-privacy/4-ethics.html">Data &amp; Privacy - Ethics Compliance</a></p><h3 id="data-protection" tabindex="-1">Data Protection <a class="header-anchor" href="#data-protection" aria-label="Permalink to &quot;Data Protection&quot;">​</a></h3><ul><li>Protect subject privacy, do not disclose personal information</li><li>Data used only for purposes stated in informed consent</li><li>Anonymize data when publishing research</li><li>Destroy or archive data according to regulations after research ends</li></ul><p>For details, see: <a href="/cogniand-manual.github.io/en/5-data-privacy/">Data &amp; Privacy</a></p><h2 id="need-help" tabindex="-1">Need Help? <a class="header-anchor" href="#need-help" aria-label="Permalink to &quot;Need Help?&quot;">​</a></h2><ul><li>Check <a href="/cogniand-manual.github.io/en/1-FAQ/">FAQ</a></li><li>Check <a href="/cogniand-manual.github.io/en/6-troubleshooting/">Troubleshooting</a></li><li>Contact <a href="/cogniand-manual.github.io/en/7-technical-support/1-contact.html">Technical Support</a></li></ul><hr><p><strong>Ready to start?</strong> Check <a href="./1-getting-started.html">Quick Start</a> to begin your first experiment!</p>',39)])])}const h=i(n,[["render",r]]);export{d as __pageData,h as default};
